import{_ as E,C as n,c as A,o as e,j as s,G as l,a6 as r,b as o,a as d,w as a,a7 as p}from"./chunks/framework.BWh_imwd.js";const f=JSON.parse('{"title":"什么是RAG检索增强生成","description":"","frontmatter":{},"headers":[],"relativePath":"column/AIFuture/基础认知/什么是RAG检索增强生成.md","filePath":"column/AIFuture/基础认知/什么是RAG检索增强生成.md","lastUpdated":1779160644000}'),u={name:"column/AIFuture/基础认知/什么是RAG检索增强生成.md"};function c(b,t,m,_,g,B){const h=n("ArticleMetadata"),i=n("Mermaid");return e(),A("div",null,[t[2]||(t[2]=s("h1",{id:"什么是rag检索增强生成",tabindex:"-1"},[d("什么是RAG检索增强生成 "),s("a",{class:"header-anchor",href:"#什么是rag检索增强生成","aria-label":'Permalink to "什么是RAG检索增强生成"'},"​")],-1)),l(h),t[3]||(t[3]=r('<p>RAG（Retrieval-Augmented Generation，检索增强生成）是一种让大模型“先查资料，再回答”的技术方案。</p><p>它不是让模型重新训练，也不是把所有文档一次性塞进提示词，而是在用户提问时，从外部知识库中检索相关资料，再把资料作为上下文交给模型生成答案。</p><h2 id="一、为什么需要-rag" tabindex="-1">一、为什么需要 RAG <a class="header-anchor" href="#一、为什么需要-rag" aria-label="Permalink to &quot;一、为什么需要 RAG&quot;">​</a></h2><p>大模型很强，但它有三个现实限制：</p><ol><li><strong>不知道你的私有数据</strong>：公司制度、项目文档、接口说明、客户资料不会自动进入模型。</li><li><strong>知识可能过期</strong>：模型训练完成后，后续发生的变化不会自然更新。</li><li><strong>容易幻觉</strong>：缺少依据时，模型可能生成看似合理但不存在的内容。</li></ol><p>RAG 的核心价值就是把回答建立在可检索资料之上。</p><h2 id="二、rag-的基本流程" tabindex="-1">二、RAG 的基本流程 <a class="header-anchor" href="#二、rag-的基本流程" aria-label="Permalink to &quot;二、RAG 的基本流程&quot;">​</a></h2>',7)),(e(),o(p,null,{default:a(()=>[l(i,{id:"mermaid-38",class:"mermaid",graph:"flowchart%20TD%0A%20%20A%5B%22%E7%94%A8%E6%88%B7%E6%8F%90%E9%97%AE%22%5D%20--%3E%20B%5B%22%E9%97%AE%E9%A2%98%E7%90%86%E8%A7%A3%E4%B8%8E%E6%94%B9%E5%86%99%22%5D%0A%20%20B%20--%3E%20C%5B%22%E6%A3%80%E7%B4%A2%E7%9F%A5%E8%AF%86%E5%BA%93%22%5D%0A%20%20C%20--%3E%20D%5B%22%E5%8F%AC%E5%9B%9E%E7%9B%B8%E5%85%B3%E7%89%87%E6%AE%B5%22%5D%0A%20%20D%20--%3E%20E%5B%22%E9%87%8D%E6%8E%92%E4%B8%8E%E8%BF%87%E6%BB%A4%22%5D%0A%20%20E%20--%3E%20F%5B%22%E6%8B%BC%E6%8E%A5%E4%B8%8A%E4%B8%8B%E6%96%87%22%5D%0A%20%20F%20--%3E%20G%5B%22%E5%A4%A7%E6%A8%A1%E5%9E%8B%E7%94%9F%E6%88%90%E7%AD%94%E6%A1%88%22%5D%0A%20%20G%20--%3E%20H%5B%22%E8%BF%94%E5%9B%9E%E7%AD%94%E6%A1%88%20%2B%20%E6%9D%A5%E6%BA%90%22%5D%0A"})]),fallback:a(()=>[...t[0]||(t[0]=[d(" Loading... ",-1)])]),_:1})),t[4]||(t[4]=r(`<p>简单理解：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>问题 → 找资料 → 带着资料问模型 → 输出答案</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="三、一个例子" tabindex="-1">三、一个例子 <a class="header-anchor" href="#三、一个例子" aria-label="Permalink to &quot;三、一个例子&quot;">​</a></h2><p>用户问：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>公司差旅报销中，高铁一等座能报销吗？</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>没有 RAG 时，模型可能基于通用经验回答，甚至胡编制度。</p><p>有 RAG 时，系统会先检索：</p><ul><li>《差旅报销制度.md》</li><li>《财务审批规则.pdf》</li><li>《2026费用报销补充说明.docx》</li></ul><p>然后把相关条款交给模型：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请基于以下制度条款回答用户问题。</span></span>
<span class="line"><span>如果资料没有明确说明，请不要自行推断。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>最终答案可以包含：</p><ul><li>结论</li><li>适用条件</li><li>原文依据</li><li>不确定事项</li><li>后续操作建议</li></ul><h2 id="四、rag-系统由哪些模块组成" tabindex="-1">四、RAG 系统由哪些模块组成 <a class="header-anchor" href="#四、rag-系统由哪些模块组成" aria-label="Permalink to &quot;四、RAG 系统由哪些模块组成&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模块</th><th>作用</th><th>关键问题</th></tr></thead><tbody><tr><td>文档采集</td><td>获取 PDF、网页、Markdown、数据库内容</td><td>数据是否完整</td></tr><tr><td>文档清洗</td><td>去掉无效内容，保留正文和结构</td><td>是否保留标题层级</td></tr><tr><td>文档切片</td><td>把长文拆成可检索片段</td><td>切多大合适</td></tr><tr><td>Embedding</td><td>把文本转成向量</td><td>语义是否准确</td></tr><tr><td>向量数据库</td><td>存储向量和元数据</td><td>检索是否快</td></tr><tr><td>召回</td><td>找到可能相关的片段</td><td>有没有漏掉</td></tr><tr><td>重排</td><td>从候选片段中选最相关的</td><td>是否真的相关</td></tr><tr><td>生成</td><td>基于资料回答</td><td>是否引用来源</td></tr><tr><td>评估</td><td>检查答案质量</td><td>是否可持续优化</td></tr></tbody></table><h2 id="五、rag-和微调有什么区别" tabindex="-1">五、RAG 和微调有什么区别 <a class="header-anchor" href="#五、rag-和微调有什么区别" aria-label="Permalink to &quot;五、RAG 和微调有什么区别&quot;">​</a></h2><table tabindex="0"><thead><tr><th>对比项</th><th>RAG</th><th>微调</th></tr></thead><tbody><tr><td>适合问题</td><td>查资料、问文档、更新频繁的知识</td><td>学习固定风格、格式、任务习惯</td></tr><tr><td>数据更新</td><td>更新知识库即可</td><td>通常需要重新训练</td></tr><tr><td>可追溯性</td><td>可以引用原文</td><td>难以说明依据</td></tr><tr><td>成本</td><td>工程复杂但更新灵活</td><td>训练成本更高</td></tr><tr><td>典型场景</td><td>企业知识库、客服、文档问答</td><td>分类器、风格迁移、专用格式输出</td></tr></tbody></table><p>经验上：<strong>需要事实依据和持续更新，优先考虑 RAG；需要模型学会特定行为，再考虑微调。</strong></p><h2 id="六、rag-的常见失败原因" tabindex="-1">六、RAG 的常见失败原因 <a class="header-anchor" href="#六、rag-的常见失败原因" aria-label="Permalink to &quot;六、RAG 的常见失败原因&quot;">​</a></h2><h3 id="_6-1-文档切片不合理" tabindex="-1">6.1 文档切片不合理 <a class="header-anchor" href="#_6-1-文档切片不合理" aria-label="Permalink to &quot;6.1 文档切片不合理&quot;">​</a></h3><p>切片太大，检索结果不精准；切片太小，答案缺少上下文。</p><p>建议：</p><ul><li>技术文档按标题层级切</li><li>FAQ 按问答对切</li><li>制度文档按条款切</li><li>长文保留前后重叠片段</li></ul><h3 id="_6-2-只做向量检索" tabindex="-1">6.2 只做向量检索 <a class="header-anchor" href="#_6-2-只做向量检索" aria-label="Permalink to &quot;6.2 只做向量检索&quot;">​</a></h3><p>向量检索擅长语义相似，但对编号、产品型号、人名、订单号这类精确匹配不一定稳定。</p><p>企业知识库通常需要：</p>`,25)),(e(),o(p,null,{default:a(()=>[l(i,{id:"mermaid-347",class:"mermaid",graph:"flowchart%20LR%0A%20%20A%5B%22%E5%85%B3%E9%94%AE%E8%AF%8D%E6%A3%80%E7%B4%A2%22%5D%20--%3E%20D%5B%22%E5%80%99%E9%80%89%E7%BB%93%E6%9E%9C%22%5D%0A%20%20B%5B%22%E5%90%91%E9%87%8F%E6%A3%80%E7%B4%A2%22%5D%20--%3E%20D%0A%20%20C%5B%22%E4%B8%9A%E5%8A%A1%E8%BF%87%E6%BB%A4%22%5D%20--%3E%20D%0A%20%20D%20--%3E%20E%5B%22%E9%87%8D%E6%8E%92%22%5D%0A%20%20E%20--%3E%20F%5B%22%E6%9C%80%E7%BB%88%E4%B8%8A%E4%B8%8B%E6%96%87%22%5D%0A"})]),fallback:a(()=>[...t[1]||(t[1]=[d(" Loading... ",-1)])]),_:1})),t[5]||(t[5]=r('<h3 id="_6-3-没有权限控制" tabindex="-1">6.3 没有权限控制 <a class="header-anchor" href="#_6-3-没有权限控制" aria-label="Permalink to &quot;6.3 没有权限控制&quot;">​</a></h3><p>RAG 不是把所有资料放进一个池子里给所有人查。每个文档片段都应该带上权限、部门、项目、来源等元数据。</p><h3 id="_6-4-没有评估集" tabindex="-1">6.4 没有评估集 <a class="header-anchor" href="#_6-4-没有评估集" aria-label="Permalink to &quot;6.4 没有评估集&quot;">​</a></h3><p>没有测试问题，就不知道优化是否真的有效。</p><p>建议准备四类问题：</p><ul><li>高频真实问题</li><li>容易混淆的问题</li><li>没有答案的问题</li><li>权限隔离问题</li></ul><h2 id="七、适合落地的场景" tabindex="-1">七、适合落地的场景 <a class="header-anchor" href="#七、适合落地的场景" aria-label="Permalink to &quot;七、适合落地的场景&quot;">​</a></h2><ul><li>企业制度问答</li><li>产品文档助手</li><li>内部研发知识库</li><li>客服辅助回复</li><li>合同条款检索</li><li>代码仓库问答</li><li>售前方案资料检索</li></ul><p>这些场景有一个共同点：<strong>答案必须来自资料，而不是模型自由发挥。</strong></p><h2 id="八、延伸阅读" tabindex="-1">八、延伸阅读 <a class="header-anchor" href="#八、延伸阅读" aria-label="Permalink to &quot;八、延伸阅读&quot;">​</a></h2><ul><li><a href="https://docs.langchain.com/oss/python/langchain/rag" target="_blank" rel="noreferrer">LangChain：Build a RAG agent</a></li><li><a href="https://developers.llamaindex.ai/python/framework/understanding/rag/" target="_blank" rel="noreferrer">LlamaIndex：Introduction to RAG</a></li><li><a href="https://developers.openai.com/api/docs/guides/tools-file-search" target="_blank" rel="noreferrer">OpenAI：File Search</a></li><li><a href="https://developers.openai.com/cookbook/examples/evaluation/evaluate_rag_with_llamaindex" target="_blank" rel="noreferrer">OpenAI Cookbook：Evaluate RAG with LlamaIndex</a></li></ul><p>一句话总结：</p><blockquote><p>RAG 让大模型从“凭记忆回答”变成“带资料回答”。</p></blockquote>',13))])}const x=E(u,[["render",c]]);export{f as __pageData,x as default};
